package report

const reportInteractiveCSS = `.finding-filters{border:1px solid var(--rule);background:var(--ink-3);padding:18px;margin:0 0 22px;display:grid;gap:16px}.filter-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.finding-filters label,.filter-group legend{display:flex;flex-direction:column;gap:7px;color:var(--paper-mute);font-size:10px;text-transform:uppercase;letter-spacing:.14em}.finding-filters input,.finding-filters select{width:100%;border:1px solid var(--rule);background:var(--ink);color:var(--paper);padding:8px 10px;font:12px var(--mono)}.finding-filters select{min-height:96px}.finding-filters input:focus-visible,.finding-filters select:focus-visible,.finding-filters button:focus-visible{outline:2px solid var(--forge);outline-offset:3px}.filter-group{border:0;display:flex;align-items:center;gap:14px;flex-wrap:wrap}.filter-group legend{margin-right:4px}.filter-group .radio{flex-direction:row;align-items:center;text-transform:none;letter-spacing:0;font-size:12px;color:var(--paper-dim)}.filter-group input{width:auto}.filter-actions{display:flex;justify-content:space-between;align-items:center;gap:16px}.filter-actions button{border:1px solid var(--forge);background:var(--forge);color:var(--ink);padding:9px 12px;font:700 12px var(--mono);cursor:pointer}.filter-count{color:var(--paper-dim);font-size:12px}.finding-group{border-top:1px solid var(--rule);padding-top:10px}.finding-group-title{font:700 11px var(--mono);letter-spacing:.14em;text-transform:uppercase;color:var(--paper-dim);margin:12px 0 2px}@media(max-width:900px){.filter-grid{grid-template-columns:1fr 1fr}.filter-actions{align-items:flex-start;flex-direction:column}}@media(max-width:560px){.filter-grid{grid-template-columns:1fr}.finding{grid-template-columns:1fr}.points{text-align:left;padding-left:0}}`

const reportInteractiveJS = `const form=document.querySelector('[data-finding-filters]');const list=document.querySelector('[data-findings-list]');if(form&&list){const severitySelect=form.elements.severity;const pillarSelect=form.elements.pillar;const pathInput=form.elements.path;const queryInput=form.elements.q;const countOutput=form.querySelector('[data-filter-count]');const clearButton=form.querySelector('[data-clear-filters]');const severityOrder=Array.from(severitySelect.options).map(option=>option.value);const pillarOrder=Array.from(pillarSelect.options).map(option=>option.value);const groupOrder=['none','file','rule'];const source=Array.from(list.querySelectorAll('.finding')).map((node,index)=>({index,node:node.cloneNode(true),severity:node.dataset.severity||'',pillar:node.dataset.pillar||'',file:node.dataset.file||'',rule:node.dataset.rule||'',search:(node.dataset.search||'').toLowerCase()}));function selected(select){return Array.from(select.selectedOptions).map(option=>option.value);}function setSelected(select,values){const allowed=new Set(values);Array.from(select.options).forEach(option=>{option.selected=allowed.has(option.value);});}function radio(){const checked=form.querySelector('input[name="group"]:checked');return checked?checked.value:'none';}function setRadio(value){const target=groupOrder.includes(value)?value:'none';const input=form.querySelector('input[name="group"][value="'+target+'"]');if(input){input.checked=true;}}function parseList(value,allowed){if(!value){return [];}const allowedSet=new Set(allowed);return value.split(',').map(item=>item.trim()).filter(item=>allowedSet.has(item));}function readHash(){const params=new URLSearchParams(window.location.hash.replace(/^#/,''));setSelected(severitySelect,parseList(params.get('severity'),severityOrder));setSelected(pillarSelect,parseList(params.get('pillar'),pillarOrder));pathInput.value=params.get('path')||'';queryInput.value=params.get('q')||'';setRadio(params.get('group')||'none');}function filters(){return{severity:selected(severitySelect),pillar:selected(pillarSelect),path:pathInput.value.trim().toLowerCase(),q:queryInput.value.trim().toLowerCase(),group:radio()};}function writeHash(){const state=filters();const parts=[];const orderedSeverity=severityOrder.filter(value=>state.severity.includes(value));const orderedPillar=pillarOrder.filter(value=>state.pillar.includes(value));if(orderedSeverity.length){parts.push('severity='+orderedSeverity.map(encodeURIComponent).join(','));}if(orderedPillar.length){parts.push('pillar='+orderedPillar.map(encodeURIComponent).join(','));}if(state.path){parts.push('path='+encodeURIComponent(state.path));}if(state.q){parts.push('q='+encodeURIComponent(state.q));}if(state.group!=='none'){parts.push('group='+encodeURIComponent(state.group));}const next=parts.length?'#'+parts.join('&'):window.location.pathname+window.location.search;history.replaceState(null,'',next);}function matches(item,state){return(state.severity.length===0||state.severity.includes(item.severity))&&(state.pillar.length===0||state.pillar.includes(item.pillar))&&(state.path===''||item.file.toLowerCase().includes(state.path))&&(state.q===''||item.search.includes(state.q));}function emptyNode(text){const node=document.createElement('div');node.className='empty';node.textContent=text;return node;}function groupTitle(value){const node=document.createElement('h3');node.className='finding-group-title';node.textContent=value;return node;}function render(){const state=filters();const visible=source.filter(item=>matches(item,state));list.replaceChildren();if(visible.length===0){list.append(emptyNode(source.length===0?'No findings.':'No findings match the active filters.'));}else if(state.group==='none'){visible.forEach(item=>list.append(item.node.cloneNode(true)));}else{const groups=new Map();visible.forEach(item=>{const key=state.group==='file'?item.file:item.rule;if(!groups.has(key)){groups.set(key,[]);}groups.get(key).push(item);});groups.forEach((items,key)=>{const section=document.createElement('section');section.className='finding-group';section.append(groupTitle(key));items.forEach(item=>section.append(item.node.cloneNode(true)));list.append(section);});}if(countOutput){countOutput.textContent=visible.length+' of '+source.length+' findings shown.';}}function update(){writeHash();render();}form.addEventListener('change',update);form.addEventListener('input',event=>{if(event.target===pathInput||event.target===queryInput){update();}});if(clearButton){clearButton.addEventListener('click',()=>{setSelected(severitySelect,[]);setSelected(pillarSelect,[]);pathInput.value='';queryInput.value='';setRadio('none');update();});}window.addEventListener('hashchange',()=>{readHash();render();});readHash();render();}`
